// src/pages/gov/NGOsPage.jsx
import { useState, useEffect } from "react";
import { useToast }            from "../../context/ToastContext";
import PageHeader              from "../../components/shared/PageHeader";
import DataTable               from "../../components/shared/DataTable";
import Badge                   from "../../components/shared/Badge";
import { ngoApi }              from "../../services/api";

export default function NGOsPage() {
  const toast = useToast();
  const [ngos,     setNgos]    = useState([]);
  const [fetching, setFetching] = useState(true);

  useEffect(() => {
    ngoApi.getAll()
      .then((res) => setNgos(res.data || []))
      .catch(() => toast("Failed to load NGOs", "error"))
      .finally(() => setFetching(false));
  }, []);

  return (
    <div>
      <PageHeader title="All NGOs" desc="Non-governmental organizations on the platform" />
      <div className="card">
        {fetching ? (
          <p style={{ color: "var(--text-muted)" }}>Loading…</p>
        ) : (
          <DataTable
            columns={[
              { key: "id",       label: "NGO ID",      mono: true },
              { key: "name",     label: "Organization" },
              { key: "focus",    label: "Focus Area" },
              { key: "admin",    label: "Admin Email" },
              { key: "funds",    label: "Funds" },
              { key: "verified", label: "Status", render: (r) => r.verified ? <Badge type="green">Verified</Badge> : <Badge type="red">Pending</Badge> },
            ]}
            data={ngos}
          />
        )}
      </div>
    </div>
  );
}
